package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	Author  string
	Message string
}

func main() {
	http.HandleFunc("/comments", displayComments)
	http.ListenAndServe(":8080", nil)
}

func displayComments(w http.ResponseWriter, r *http.Request) {
	if r.Method == "GET" {
		tmpl := template.Must(template.ParseFiles("comments.html"))
		comments := []Comment{
			{Author: "Alice", Message: "Hello <b>World</b>!"},
			{Author: "Bob", Message: "This is a <i>comment</i>."},
		}
		tmpl.Execute(w, comments)
	} else {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
	}
}